"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[763],{2295:(t,r,e)=>{e.r(r),e.d(r,{data:()=>n});const n=JSON.parse('{"key":"v-2689f6e0","path":"/%D0%BF%D1%80%D0%B5%D0%B4%D0%BC%D0%B5%D1%82%D1%8B-%D0%B8-%D1%84%D0%BE%D1%80%D0%BC%D1%8B-%D0%B4%D0%B5%D1%8F%D1%82%D0%B5%D0%BB%D1%8C%D0%BD%D0%BE%D1%81%D1%82%D0%B8.html","title":"Предметы и формы деятельности","lang":"ru-RU","frontmatter":{"title":"Предметы и формы деятельности","date":"2024-02-15","categories":["Самообразование"],"tags":["Идеальное"]},"excerpt":"","headers":[],"git":{"updatedTime":1708027844000},"filePathRelative":"предметы-и-формы-деятельности.md"}')},254:(t,r,e)=>{e.r(r),e.d(r,{default:()=>h});var n=e(6252),l=e(3577);const a={id:"frontmatter-title",tabindex:"-1"},s=(0,n._)("a",{class:"header-anchor",href:"#frontmatter-title","aria-hidden":"true"},"#",-1),o=(0,n._)("p",null,[(0,n._)("strong",null,"15.02.2024")],-1),D=(0,n._)("p",null,"Идея товарного фетишизма звучит обманчиво просто: под свойством вещи, на самом деле, скрыты общественные отношения. В физическом теле товара нет ничего связанного со стоимостью. Стоимость находится в другой плоскости — в плоскости отношений между людьми. Похожие явления можно найти и вне политэкономии.",-1),p=(0,n._)("p",null,[(0,n.Uk)("Если станок перевести на остров, населённый неразвитым обществом, то он не сможет выполнять роль средства производства. В обществе может быть не сформирована такая роль, отсутствовать определенная форма отношений между людьми. То же самое будет, если на этот остров перевезти картину. "),(0,n._)("strong",null,"Для людей"),(0,n.Uk)(" она будет представлять совершенно другой объект по сравнению с обществом откуда она изъята. Вполне возможно, картина будет функционировать только в качестве своего тела — физического объекта. Особенно ярко это можно представить на примере абстрактных картин, вроде Черного квадрата. Нечто внешнее, по отношению к физическому объекту, делает картину картиной.")],-1),i=(0,n._)("p",null,"В одной из книг, Евгений Богат говорит о том, что за столетия некоторые картины изменились, показывают не то, что показывали раньше. Однако холст и краски на картине остались прежними, или, может быть, только постарели со временем. Но на картине видят уже не то, что видели раньше. В каком же пространстве люди видят изменения в картине? Куда заглядывают люди когда «смотрят на картину»?",-1),u=(0,n._)("p",null,"С книгой ситуация аналогична картине. Понимание книги меняется со временем, несмотря на то, что слова остаются неизменными. Возьмем ситуацию: идет обсуждение книги, автор книги умер в прошлом веке или ещё раньше. Кто-то соглашается с мыслями из книги, кто-то их критикует. Может показаться, что тот с кем соглашаются или кого критикуют — автор книги. Но это только внешняя форма, хотя бы уже потому, что автора давно нет в живых. Автора нет, но некоторым способом он существует через тех людей которые переняли его идеи. Действительный объект критики — те люди которые поддерживают убеждения автора, неважно, непосредственно они находятся в обсуждении или нет.",-1),g={href:"https://www.kinopoisk.ru/series/585282/",target:"_blank",rel:"noopener noreferrer"},B=(0,n.uE)("<p>Можно предположить, что направляя взгляд на картину, человек на самом деле смотрит внутрь себя. На этом моменте снова возникает опасность фетишизации, ошибки когда за свойство предмета — человеческого тела или мозга, принимают нечто связанное с ним, но не тождественное. Измерение в котором находится картина, книги и личность человека сложно зафиксировать в том смысле как анатомия разделяет тело организма на органы. Картину нельзя найти в физическом объекте, а личность не получится обнаружить в биологическом организме, но во внешних, по отношению к ним <strong>предметах</strong>, поиски так же не приведут к результату.</p><p>Личность и картина существуют внутри системы в которой люди производят и обмениваются предметами. Переход вещи, в деятельность по созданию этой вещи, затем в слово или знак этой деятельности и обратно — в деятельность и снова в вещь, составляют суть вышеназванных предметов: картины и личности. Способ деятельности существует только когда <strong>делается</strong>, только в процессе, в движении. Любая форма его фиксации: в мозге или на бумаге будет только одним из его статичных состояний. Физический предмет попадает в круговорот человеческой деятельности и наделяется определенной ролью внутри общественной системы. Эта деятельность-роль связанная с предметом и есть <strong>человеческий предмет</strong>. На этот предмет, на способ деятельности, «смотрят» люди вглядываясь в картину.</p><p>Развитие форм деятельности, а не только изменение предметов, составляет общественный прогресс. Особенность <strong>человеческих</strong> форм деятельности в отделении от непосредственной активности организма, в том сами эти формы могут быть зафиксированы в виде отдельных предметов: слов, чертежей и любых других. Отдельность форм деятельности и их фиксация в вещах позволяют рассматривать и изменять их отдельно от непосредственной деятельности. Конечно, с последующей реализацией непосредственной деятельности. Кроме общества в целом, это так же касается результатов работы небольшой группы людей, самообразовательного сообщества, кружка.</p><p>Если результат работы, проявляется только в появлении новых мозговых структур, новом наборе слов или другой фиксированной форме, то работа не эффективна. Необходимая цель работы сообщества — развитие способности видеть и менять формы деятельности, прежде всего свои собственные, индивидуальные и коллективные. Признак понимания — не возможность повторить идею, а действие в соответствии с этой идеей, даже если, в определенных условиях, действие может быть сведено до воспроизведения и передачи слов. Текст, рассказ или критика, не ставшие причиной изменения форм деятельности участников, остаются зернами которые не проросли и погибли. Забывая это — теряется фокус, акцент на цели — изменении людей, а изменение людей не может быть чем-то другим кроме изменения общественных отношений, форм деятельности.</p><p>Переданный от одного человека предмет, пусть даже этот предмет слово, должен продолжатся в действии другого человека. Если второй человек не включается в процесс, не переводит предмет в <strong>своё</strong> действие, то цепочка прерывается. Если же человек меняется — меняет свой способ действия, то возникает цепная реакция — он изменяет других людей. Внешние условия, «объективный фактор», могут способствовать этому или противостоять, но принцип от этого не меняется: люди меняют людей и при совпадении этого процесса с изменением обстоятельств происходит коренное преобразование общества.</p>",5),d={},h=(0,e(3744).Z)(d,[["render",function(t,r){const e=(0,n.up)("ExternalLinkIcon");return(0,n.wg)(),(0,n.iD)("div",null,[(0,n._)("h1",a,[s,(0,n.Uk)(" "+(0,l.zw)(t.$frontmatter.title),1)]),o,D,p,i,u,(0,n._)("p",null,[(0,n.Uk)("В фильме "),(0,n._)("a",g,[(0,n.Uk)("Столик в углу"),(0,n.Wm)(e)]),(0,n.Uk)(", загадочный человек «исполняет желания» людей в обмен на выполнение некоторого задания. В одном из сюжетов, парень захотел стать бессмертным и вечно молодым. Человек за столиком попросил его «пометить пять человек». Что это значит было непонятно. Сначала парень попробовал ударить другого человека, сломать ему нос. Оказалось, что такой способ «пометить» человека не подходит. Затем парень встретил девушку, они начали общаться и он почувствовал, что он сам и девушка изменились. Не делают ли такого рода «пометки» людей «бессмертными»?")]),B])}]])}}]);